+        if let Some(ref mut backing) = self.mem_backing {
+            let data = backing.read(remaining);
+            if data.is_empty() && result.is_empty() {
+                self.flags.eof = true;
+            }
+            result.extend(data);
+            self.offset = backing.position() as i64;
+        }
+        result
+    }
